class Solution:
    def levelOrder(self, root: Optional[TreeNode]) -> list[list[int]]:
        result = []

        def dfs(node, depth):
            if not node:
                return
            # Ensure result has a list for this depth
            if depth == len(result):
                result.append([])
            result[depth].append(node.val)
            dfs(node.left, depth + 1)
            dfs(node.right, depth + 1)

        dfs(root, 0)
        return result

