        def dfs(node, depth):
            if not node:
                return
            if depth == len(result):  # first time seeing this depth
                result.append(node.val)
            dfs(node.right, depth + 1)  # right first
            dfs(node.left, depth + 1)

        dfs(root, 0)
        return result

class Solution:
    def goodNodes(self, root: TreeNode) -> int:
        def dfs(node, path_max):
            if not node:
                return 0
            count = 1 if node.val >= path_max else 0
            new_max = max(path_max, node.val)
            count += dfs(node.left, new_max)
            count += dfs(node.right, new_max)
            return count

        return dfs(root, root.val)

class Solution:
    def isValidBST(self, root: Optional[TreeNode]) -> bool:
        def valid(node, min_val, max_val):
            if not node:
                return True
            if not (min_val < node.val < max_val):
                return False
            return valid(node.left, min_val, node.val) and valid(node.right, node.val, max_val)

        return valid(root, float('-inf'), float('inf'))

class Solution:
    def isValidBST(self, root: Optional[TreeNode]) -> bool:
        prev = float('-inf')

        def inorder(node):
            nonlocal prev
            if not node:
                return True
            if not inorder(node.left):
                return False
            if node.val <= prev:
                return False
            prev = node.val
            return inorder(node.right)

        return inorder(root)

class Solution:
    def kthSmallest(self, root: Optional[TreeNode], k: int) -> int:
        count = 0
        result = None

        def inorder(node):
            nonlocal count, result
            if not node or result is not None:
                return
            inorder(node.left)
            count += 1
            if count == k:
                result = node.val
                return
            inorder(node.right)

        inorder(root)
        return result

class Solution:
    def buildTree(self, preorder: list[int], inorder: list[int]) -> Optional[TreeNode]:
        # Map value -> index in inorder for O(1) lookup
        inorder_map = {val: i for i, val in enumerate(inorder)}

        def build(pre_start, pre_end, in_start, in_end):
            if pre_start > pre_end:
                return None
            root_val = preorder[pre_start]
            root = TreeNode(root_val)
            in_root = inorder_map[root_val]
            left_size = in_root - in_start
            # Build left subtree
            root.left = build(pre_start + 1, pre_start + left_size, in_start, in_root - 1)
            # Build right subtree
            root.right = build(pre_start + left_size + 1, pre_end, in_root + 1, in_end)
            return root

        return build(0, len(preorder) - 1, 0, len(inorder) - 1)

