class Codec:
    def serialize(self, root):
        """Encodes a tree to a single string."""
        result = []
        def dfs(node):
            if not node:
                result.append('N')
                return
            result.append(str(node.val))
            dfs(node.left)
            dfs(node.right)
        dfs(root)
        return ','.join(result)

    def deserialize(self, data):
        """Decodes your encoded data to tree."""
        tokens = iter(data.split(','))
        def dfs():
            val = next(tokens)
            if val == 'N':
                return None
            node = TreeNode(int(val))
            node.left = dfs()
            node.right = dfs()
            return node
        return dfs()
